// =============================================================
// PASO 1 — DATA GATHERING / INGESTA (formato estándar)
// =============================================================
// Formato estándar de entrada por SKU. Reemplaza este nodo por un
// nodo "Google Sheets > Read rows" cuando tengas la planilla:
//   columnas: marca, sku, mes(1-12), unidades, precio_unitario, costo_unitario
//
// Aquí va 1 SKU de chocolate con 24 meses de histórico real de ventas
// (unidades). El motor proyectará los próximos 12 meses.

const config = {
  marca: 'ChocoAndes',
  sku: 'BARRA-70CACAO-100G',
  unidad: 'unidades',
  precio_unitario: 1890,      // CLP
  costo_unitario: 1100,       // CLP (COGS)
  moneda: 'CLP',
  hemisferio: 'sur',          // Chile: invierno Jun-Ago = peak chocolate
  horizonte_meses: 12
};

// Histórico de ventas (mes calendario 1..12 -> unidades). 24 meses.
// Tendencia suave al alza + estacionalidad (peak invierno + Navidad + Pascua).
const historico = [
  { anio: 2024, mes: 1,  unidades: 8200 },
  { anio: 2024, mes: 2,  unidades: 7900 },
  { anio: 2024, mes: 3,  unidades: 11200 }, // Pascua
  { anio: 2024, mes: 4,  unidades: 10100 },
  { anio: 2024, mes: 5,  unidades: 12800 },
  { anio: 2024, mes: 6,  unidades: 15600 }, // invierno
  { anio: 2024, mes: 7,  unidades: 16200 },
  { anio: 2024, mes: 8,  unidades: 15100 },
  { anio: 2024, mes: 9,  unidades: 12400 },
  { anio: 2024, mes: 10, unidades: 11800 },
  { anio: 2024, mes: 11, unidades: 12900 },
  { anio: 2024, mes: 12, unidades: 17800 }, // Navidad
  { anio: 2025, mes: 1,  unidades: 8800 },
  { anio: 2025, mes: 2,  unidades: 8400 },
  { anio: 2025, mes: 3,  unidades: 12100 },
  { anio: 2025, mes: 4,  unidades: 11000 },
  { anio: 2025, mes: 5,  unidades: 13700 },
  { anio: 2025, mes: 6,  unidades: 16800 },
  { anio: 2025, mes: 7,  unidades: 17500 },
  { anio: 2025, mes: 8,  unidades: 16300 },
  { anio: 2025, mes: 9,  unidades: 13300 },
  { anio: 2025, mes: 10, unidades: 12600 },
  { anio: 2025, mes: 11, unidades: 13900 },
  { anio: 2025, mes: 12, unidades: 19100 }
];

return [{ json: { config, historico } }];

// =============================================================
// PASO 2 — DEMAND PLANNING: baseline estadístico
// =============================================================
// 1) Tendencia: regresión lineal sobre el histórico (nivel global)
// 2) Estacionalidad: índice por mes (promedio mes / promedio total)
// 3) Baseline = tendencia proyectada * índice estacional del mes

const { config, historico } = $input.first().json;

const n = historico.length;
const ys = historico.map(h => h.unidades);
const xs = historico.map((_, i) => i + 1);

// --- Regresión lineal simple (mínimos cuadrados) ---
const sumX = xs.reduce((a, b) => a + b, 0);
const sumY = ys.reduce((a, b) => a + b, 0);
const sumXY = xs.reduce((a, x, i) => a + x * ys[i], 0);
const sumX2 = xs.reduce((a, x) => a + x * x, 0);
const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
const intercept = (sumY - slope * sumX) / n;
const trendAt = (x) => intercept + slope * x;

// --- Índice estacional por mes calendario (1..12) ---
const mediaTotal = sumY / n;
const porMes = {};
for (let m = 1; m <= 12; m++) {
  const vals = historico.filter(h => h.mes === m).map(h => h.unidades);
  const prom = vals.reduce((a, b) => a + b, 0) / vals.length;
  porMes[m] = +(prom / mediaTotal).toFixed(4); // índice estacional
}

// --- Proyección de los próximos 'horizonte' meses ---
const nombresMes = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
const ultimo = historico[historico.length - 1];
let anio = ultimo.anio;
let mes = ultimo.mes;

const baseline = [];
for (let k = 1; k <= config.horizonte_meses; k++) {
  mes += 1; if (mes > 12) { mes = 1; anio += 1; }
  const x = n + k;
  const tendencia = trendAt(x);
  const indice = porMes[mes];
  const unidades = Math.round(tendencia * indice);
  baseline.push({
    anio, mes, mes_nombre: nombresMes[mes - 1],
    tendencia: Math.round(tendencia),
    indice_estacional: indice,
    baseline_unidades: unidades
  });
}

return [{ json: {
  config,
  modelo: { slope: +slope.toFixed(2), intercept: Math.round(intercept), media_total: Math.round(mediaTotal), indices_estacionales: porMes },
  baseline
} }];

// =============================================================
// PASO 3b — APLICAR AJUSTE AI + OVERRIDE MANUAL
// =============================================================
// Toma el baseline (nodo 2) y el factor del AI (nodo 3) y produce el
// CONSENSUS FORECAST. El planner puede sobrescribir manualmente en
// 'overrideManual' (mes_nombre -> unidades fijas).

const base = $('② Demand Planning (baseline)').first().json;
const aiText = $input.first().json.text || $input.first().json.response || '';

// --- Parseo robusto del JSON que devolvió GPT ---
let ajustes = [];
try {
  const limpio = String(aiText).replace(/```json|```/g, '').trim();
  const match = limpio.match(/\{[\s\S]*\}/);
  ajustes = JSON.parse(match ? match[0] : limpio).ajustes || [];
} catch (e) {
  ajustes = []; // si el AI falla, factor = 1.00 (degrada con gracia)
}
const factorDe = (mesNombre, anio) => {
  const a = ajustes.find(x => x.mes === mesNombre && (!x.anio || x.anio === anio));
  return a ? { factor: Math.max(0.8, Math.min(1.2, Number(a.factor) || 1)), razon: a.razon || '' } : { factor: 1, razon: 'sin ajuste AI' };
};

// --- OVERRIDE MANUAL del planner (edítalo aquí o vía Google Sheets) ---
const overrideManual = {
  // 'Dic': 21000,
};

const demand = base.baseline.map(b => {
  const { factor, razon } = factorDe(b.mes_nombre, b.anio);
  const ajustado = Math.round(b.baseline_unidades * factor);
  const manual = overrideManual[b.mes_nombre];
  const consensus = manual != null ? manual : ajustado;
  return {
    anio: b.anio, mes: b.mes, mes_nombre: b.mes_nombre,
    baseline_unidades: b.baseline_unidades,
    factor_ai: factor,
    razon_ai: razon,
    demanda_ajustada_ai: ajustado,
    override_manual: manual != null ? manual : null,
    consensus_forecast: consensus
  };
});

return [{ json: { config: base.config, demand } }];

// =============================================================
// PASO 4 — SUPPLY PLANNING: capacidad de fábrica vs demanda
// =============================================================
const { config, demand } = $input.first().json;

// Parámetros de supply (edítalos o léelos de Google Sheets / ERP):
const supply = {
  capacidad_mensual_unidades: 17000, // techo de producción por mes para este SKU
  inventario_inicial: 4000,          // stock disponible al arranque
  stock_seguridad: 2500              // colchón objetivo
};

let inventario = supply.inventario_inicial;
const plan = demand.map(d => {
  const demandaNeta = d.consensus_forecast + supply.stock_seguridad - inventario;
  const produccion_plan = Math.max(0, Math.min(supply.capacidad_mensual_unidades, demandaNeta));
  const disponible = inventario + produccion_plan;
  const ventas = Math.min(disponible, d.consensus_forecast);
  const quiebre = Math.max(0, d.consensus_forecast - disponible); // demanda no satisfecha
  const utilizacion = +(produccion_plan / supply.capacidad_mensual_unidades).toFixed(3);
  inventario = disponible - ventas;
  return {
    anio: d.anio, mes_nombre: d.mes_nombre,
    consensus_forecast: d.consensus_forecast,
    produccion_plan,
    utilizacion_capacidad: utilizacion,
    inventario_cierre: Math.round(inventario),
    quiebre_unidades: quiebre,
    alerta: quiebre > 0 ? '🔴 QUIEBRE: capacidad insuficiente' : (utilizacion > 0.95 ? '🟠 Capacidad al límite' : '🟢 OK')
  };
});

return [{ json: { config, supply, plan } }];

// =============================================================
// PASO 5 — RECONCILIACIÓN FINANCIERA
// =============================================================
const { config, supply, plan } = $input.first().json;
const P = config.precio_unitario;
const C = config.costo_unitario;

const fin = plan.map(p => {
  const ventas_unid = p.consensus_forecast - p.quiebre_unidades;
  const ingresos = ventas_unid * P;
  const costo = p.produccion_plan * C;
  const margen_bruto = ingresos - (ventas_unid * C);
  return {
    anio: p.anio, mes_nombre: p.mes_nombre,
    ventas_unid,
    ingresos,
    costo_produccion: costo,
    margen_bruto,
    margen_pct: ingresos ? +((margen_bruto / ingresos) * 100).toFixed(1) : 0,
    venta_perdida_quiebre: p.quiebre_unidades * P
  };
});

const tot = (k) => fin.reduce((a, x) => a + x[k], 0);
const totales = {
  ingresos_total: tot('ingresos'),
  margen_bruto_total: tot('margen_bruto'),
  margen_pct_promedio: +((tot('margen_bruto') / tot('ingresos')) * 100).toFixed(1),
  venta_perdida_total: tot('venta_perdida_quiebre'),
  unidades_total: tot('ventas_unid')
};

return [{ json: { config, fin, totales, supply, plan } }];

// =============================================================
// PASO 6 — EXECUTIVE REVIEW: plan consensuado + alertas
// =============================================================
const { config, fin, totales, plan } = $input.first().json;
const fmt = (n) => new Intl.NumberFormat('es-CL').format(Math.round(n));

const alertas = plan.filter(p => p.alerta !== '🟢 OK');
const fmtMon = (n) => `${config.moneda} ${fmt(n)}`;

let resumen = `📊 PLAN S&OP — ${config.marca} / ${config.sku}\n`;
resumen += `Horizonte: ${config.horizonte_meses} meses\n`;
resumen += `\n— RESULTADO FINANCIERO —\n`;
resumen += `Volumen total:     ${fmt(totales.unidades_total)} ${config.unidad}\n`;
resumen += `Ingresos:          ${fmtMon(totales.ingresos_total)}\n`;
resumen += `Margen bruto:      ${fmtMon(totales.margen_bruto_total)} (${totales.margen_pct_promedio}%)\n`;
resumen += `Venta perdida x quiebre: ${fmtMon(totales.venta_perdida_total)}\n`;
resumen += `\n— ALERTAS DE SUPPLY (${alertas.length}) —\n`;
resumen += alertas.length
  ? alertas.map(a => `${a.mes_nombre} ${a.anio}: ${a.alerta} (quiebre ${fmt(a.quiebre_unidades)}u, util ${(a.utilizacion_capacidad*100).toFixed(0)}%)`).join('\n')
  : 'Sin alertas: capacidad cubre la demanda consensuada.';
resumen += `\n\n— DECISIÓN EJECUTIVA —\n`;
resumen += alertas.length
  ? '⚠️ Requiere decisión: ampliar capacidad / turno extra / adelantar producción / repriorizar SKU.'
  : '✅ Plan aprobable sin restricciones de capacidad.';

return [{ json: { resumen, totales, fin, plan, config } }];
